class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>().ToContainer("Products");

        // EF9 changed the default discriminator property from "Discriminator" to "$type".
        // Existing 500K documents use "Discriminator", so we must preserve it.
        modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

        // EF9 changed id format from "Product|123" to "123".
        // Existing documents use the compound format, so we must preserve it.
        modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);

        // REMOVED: HasIndex() now throws for Cosmos entities in EF9.
        // Cosmos DB indexing is managed via the container's indexing policy
        // (Azure Portal, Bicep, or Terraform), not through EF Core.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

